mapper.select:
SELECT qbmm.id, qbmm.question_bank_id, qbmm.material_id, qbmm.sequence, qbmm.creator, qbmm.add_datetime, qbmm.operator, qbmm.operation_datetime FROM question_bank_materials_mapping qbmm LEFT JOIN teaching_materials tm ON qbmm.material_id = tm.id
qbmm.question_bank_id = #{param.questionBankId}
AND tm.name LIKE CONCAT('%', #{param.materialName}, '%')
AND tm.type = #{param.materialType}
ORDER BY qbmm.sequence ASC, qbmm.add_datetime DESC
